static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed3dSquareInputAsymmetricKernelCustomTilingData tiling;

    const auto *xShape = context->GetInputShape(0);
    const auto *wShape = context->GetInputShape(1);

    // Expect shapes:
    // x: [N, Ci, Di, Hi, Wi]
    // w: [Ci, Co, Kd, Kh, Kw]  (PyTorch ConvTranspose3d weight layout)
    const uint32_t n  = static_cast<uint32_t>(xShape->GetDim(0));
    const uint32_t ci = static_cast<uint32_t>(xShape->GetDim(1));
    const uint32_t inD = static_cast<uint32_t>(xShape->GetDim(2));
    const uint32_t inH = static_cast<uint32_t>(xShape->GetDim(3));
    const uint32_t inW = static_cast<uint32_t>(xShape->GetDim(4));

    const uint32_t w_ci = static_cast<uint32_t>(wShape->GetDim(0));
    const uint32_t co   = static_cast<uint32_t>(wShape->GetDim(1));
    const uint32_t kD   = static_cast<uint32_t>(wShape->GetDim(2));
    const uint32_t kH   = static_cast<uint32_t>(wShape->GetDim(3));
    const uint32_t kW   = static_cast<uint32_t>(wShape->GetDim(4));

    if (w_ci != ci) {
        return ge::GRAPH_FAILED;
    }

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t stride_d = attrs->GetAttrPointer<int32_t>(0) ? *(attrs->GetAttrPointer<int32_t>(0)) : 1;
    const int32_t stride_h = attrs->GetAttrPointer<int32_t>(1) ? *(attrs->GetAttrPointer<int32_t>(1)) : 1;
    const int32_t stride_w = attrs->GetAttrPointer<int32_t>(2) ? *(attrs->GetAttrPointer<int32_t>(2)) : 1;
    const int32_t pad_d    = attrs->GetAttrPointer<int32_t>(3) ? *(attrs->GetAttrPointer<int32_t>(3)) : 0;
    const int32_t pad_h    = attrs->GetAttrPointer<int32_t>(4) ? *(attrs->GetAttrPointer<int32_t>(4)) : 0;
    const int32_t pad_w    = attrs->GetAttrPointer<int32_t>(5) ? *(attrs->GetAttrPointer<int32_t>(5)) : 0;
    const int32_t dil_d    = attrs->GetAttrPointer<int32_t>(6) ? *(attrs->GetAttrPointer<int32_t>(6)) : 1;
    const int32_t dil_h    = attrs->GetAttrPointer<int32_t>(7) ? *(attrs->GetAttrPointer<int32_t>(7)) : 1;
    const int32_t dil_w    = attrs->GetAttrPointer<int32_t>(8) ? *(attrs->GetAttrPointer<int32_t>(8)) : 1;
    const int32_t out_pad_d= attrs->GetAttrPointer<int32_t>(9) ? *(attrs->GetAttrPointer<int32_t>(9)) : 0;
    const int32_t out_pad_h= attrs->GetAttrPointer<int32_t>(10)? *(attrs->GetAttrPointer<int32_t>(10)) : 0;
    const int32_t out_pad_w= attrs->GetAttrPointer<int32_t>(11)? *(attrs->GetAttrPointer<int32_t>(11)) : 0;
    const int32_t groups   = attrs->GetAttrPointer<int32_t>(12)? *(attrs->GetAttrPointer<int32_t>(12)) : 1;

    // Output shape formula (PyTorch ConvTranspose3d):
    // out = (in - 1)*stride - 2*padding + dilation*(k - 1) + output_padding + 1
    const uint32_t outD = static_cast<uint32_t>((static_cast<int64_t>(inD) - 1) * stride_d - 2 * pad_d
                        + dil_d * (kD - 1) + out_pad_d + 1);
    const uint32_t outH = static_cast<uint32_t>((static_cast<int64_t>(inH) - 1) * stride_h - 2 * pad_h
                        + dil_h * (kH - 1) + out_pad_h + 1);
    const uint32_t outW = static_cast<uint32_t>((static_cast<int64_t>(inW) - 1) * stride_w - 2 * pad_w
                        + dil_w * (kW - 1) + out_pad_w + 1);

    // Block mapping: one (n, co) pair per block (with grid-stride for excess)
    uint32_t blocks = n * co;
    if (blocks < 8u) blocks = 8u;
    if (blocks > 24u) blocks = 24u;
    context->SetBlockDim(blocks);

    tiling.set_n(n);
    tiling.set_ci(ci);
    tiling.set_co(co);
    tiling.set_inD(inD);
    tiling.set_inH(inH);
    tiling.set_inW(inW);
    tiling.set_kD(kD);
    tiling.set_kH(kH);
    tiling.set_kW(kW);
    tiling.set_outD(outD);
    tiling.set_outH(outH);
    tiling.set_outW(outW);
    tiling.set_blockDim(blocks);

    tiling.set_stride_d(stride_d);
    tiling.set_stride_h(stride_h);
    tiling.set_stride_w(stride_w);
    tiling.set_pad_d(pad_d);
    tiling.set_pad_h(pad_h);
    tiling.set_pad_w(pad_w);
    tiling.set_dilation_d(dil_d);
    tiling.set_dilation_h(dil_h);
    tiling.set_dilation_w(dil_w);
    tiling.set_output_pad_d(out_pad_d);
    tiling.set_output_pad_h(out_pad_h);
    tiling.set_output_pad_w(out_pad_w);
    tiling.set_groups(groups);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

