    y->SetDimNum(5);
    y->SetDim(0, N);
    y->SetDim(1, Co);
    y->SetDim(2, Do);
    y->SetDim(3, Ho);
    y->SetDim(4, Wo);
    return GRAPH_SUCCESS;
