#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

static inline at::Tensor empty_output_like_convtrans3d(const at::Tensor& x, const at::Tensor& w)
{
    // x: [N, Ci, D, H, W], w: [Ci, Co, kD, kH, kW]
    auto N  = x.size(0);
    auto Ci = x.size(1);
    auto Di = x.size(2);
    auto Hi = x.size(3);
    auto Wi = x.size(4);
    auto Ci_w = w.size(0);
    TORCH_CHECK(Ci == Ci_w, "Weight Ci must equal input Ci");
    auto Co = w.size(1);
    auto kD = w.size(2);
    auto kH = w.size(3);
    auto kW = w.size(4);
    // Fixed attributes (stride=1, pad=0, dilation=1, out_pad=0)
    auto Do = Di + kD - 1;
    auto Ho = Hi + kH - 1;
    auto Wo = Wi + kW - 1;
    auto options = x.options();
    return at::empty({N, Co, Do, Ho, Wo}, options);
}

at::Tensor conv_transposed_3d_square_input_asymmetric_kernel_impl_npu(const at::Tensor& x,
                                                                      const at::Tensor& weight)
{
    at::Tensor y = empty_output_like_convtrans3d(x, weight);
    EXEC_NPU_CMD(aclnnConvTransposed3dSquareInputAsymmetricKernelCustom, x, weight, y);
    return y;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("conv_transposed_3d_square_input_asymmetric_kernel_custom", &conv_transposed_3d_square_input_asymmetric_kernel_impl_npu);
}

